
import base64
import zlib
import hashlib
import sys


def __anti_debug():
    import sys
    import inspect
    
    # تحقق إذا كان الكود يجرى في مصحح أخطاء
    trace_func = sys.gettrace()
    if trace_func is not None:
        print("⚠️ تم الكشف عن مصحح أخطاء!")
        sys.exit(1)
    
    # تحقق من عمق الاستدعاءات
    frame_count = len(inspect.stack())
    if frame_count > 30:
        print("⚠️ نشاط مشبوه!")
        sys.exit(1)

def __integrity_check(data_hash):
    # فحص سلامة البيانات
    expected_hash = "522c3b405a5c791360457351095b1015b97921b1c0856e3f41407700263fa6f0"
    current_hash = hashlib.sha256(data_hash.encode()).hexdigest()
    return expected_hash == current_hash

# فحص الحماية
__anti_debug()


def __decrypt_protected(data, layers=1):
    current = data
    
    # فحص سلامة البيانات أولاً
    if not __integrity_check(data):
        print("❌ تم العبث بالبيانات!")
        sys.exit(1)
    
    for layer in range(layers-1, -1, -1):
        if layer > 0:
            try:
                current = base64.b64decode(current.encode('utf-8')).decode('utf-8')
            except:
                print("❌ تلف في البيانات المشفرة")
                sys.exit(1)
        
        # معرفة الفاصل المستخدم
        separators = ['|', '~', '^', '&', '*', '$', '@']
        separator = None
        for sep in separators:
            if sep in current:
                separator = sep
                break
        
        if not separator:
            print("❌ تنسيق غير معروف")
            sys.exit(1)
        
        # فك التشويش
        parts = current.split(separator)
        clean_parts = []
        
        for part in parts:
            if ":" in part:
                segments = part.split(":")
                if len(segments) >= 3:
                    _, _, chunk = segments[0], segments[1], ":".join(segments[2:])
                    clean_parts.append(chunk)
                else:
                    clean_parts.append(part)
            else:
                clean_parts.append(part)
        
        # إعادة ترتيب القطع (عكس العكس)
        clean_parts.reverse()
        current = "".join(clean_parts)
        
        # فك rot47
        decrypted_chars = []
        for i, char in enumerate(current):
            if 33 <= ord(char) <= 126:
                shift = 47 + (layer * 7) + (i % 13)
                new_code = ((ord(char) - 33 - shift) % 94) + 33
                decrypted_chars.append(chr(new_code))
            else:
                decrypted_chars.append(char)
        current = ''.join(decrypted_chars)
    
    # فك الضغط
    try:
        # ✨ الإصلاح: معالجة الأحرف غير الصالحة في Base85
        current_clean_b85 = ''
        for char in current:
            if char == '_':
                # استبدال '_' بـ '=' (الحرف الافتراضي في Base85)
                current_clean_b85 += '='
            else:
                current_clean_b85 += char
        
        decoded = base64.b85decode(current_clean_b85.encode('utf-8'))
        decompressed = zlib.decompress(decoded)
        return decompressed.decode('utf-8')
    except Exception as e:
        print(f"❌ خطأ في فك التشفير: {str(e)[:100]}")
        sys.exit(1)

